import{_ as a,o as i,c as e,a2 as o}from"./chunks/framework.B72_uj9U.js";const q=JSON.parse('{"title":"访谈问题库","description":"","frontmatter":{},"headers":[],"relativePath":"zh/templates/interview-questions.md","filePath":"zh/templates/interview-questions.md"}'),r={name:"zh/templates/interview-questions.md"};function t(h,l,n,u,s,d){return i(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="访谈问题库" tabindex="-1">访谈问题库 <a class="header-anchor" href="#访谈问题库" aria-label="Permalink to &quot;访谈问题库&quot;">​</a></h1><blockquote><p><strong>使用说明：</strong> 本问题库涵盖社会责任、环境、商业道德、信息安全和知识产权五个领域的访谈问题。问题按访谈对象组织。</p><ul><li><strong>工人访谈须保密进行</strong>：在无管理人员在场的独立空间中进行，开始前告知工人访谈内容保密，不会向工厂反馈个人信息</li><li><strong>开放式问题优先</strong>：优先使用开放式问题（&quot;告诉我…&quot;、&quot;请描述…&quot;）而非封闭式问题（&quot;是不是…&quot;）</li><li><strong>交叉验证</strong>：访谈结论应与现场观察和文件审查结果相互印证，避免以单一访谈结果下结论</li><li>本问题库为参考题目，审核员可根据实际情况选择和调整</li></ul></blockquote><hr><h2 id="一、工人保密访谈-csr审核用" tabindex="-1">一、工人保密访谈（CSR审核用） <a class="header-anchor" href="#一、工人保密访谈-csr审核用" aria-label="Permalink to &quot;一、工人保密访谈（CSR审核用）&quot;">​</a></h2><blockquote><p><strong>访谈对象：</strong> 工人（随机抽样，含正式工和派遣工） <strong>时间：</strong> 每人约20-30分钟 <strong>场所：</strong> 独立房间，无管理人员陪同 <strong>开场语（建议）：</strong> &quot;谢谢您抽时间和我们交流。我是来了解这里工作情况的，不是来检查您个人表现的。我们的谈话内容将保密，不会告诉工厂管理层您说了什么，也不会在报告中提到您的名字。没有标准答案，请如实告诉我您的实际体验。&quot;</p></blockquote><h3 id="_1-1-招募与入职" tabindex="-1">1.1 招募与入职 <a class="header-anchor" href="#_1-1-招募与入职" aria-label="Permalink to &quot;1.1 招募与入职&quot;">​</a></h3><ul><li>您是通过什么途径找到这份工作的？（朋友介绍/中介/招聘网站/直接到工厂）</li><li>来这里工作前，是否向中介或工厂交过任何费用（如介绍费、押金、培训费）？</li><li>入职时是否签署了劳动合同？您是否保留了合同的副本？合同内容是否向您解释清楚了？</li></ul><h3 id="_1-2-工作时间" tabindex="-1">1.2 工作时间 <a class="header-anchor" href="#_1-2-工作时间" aria-label="Permalink to &quot;1.2 工作时间&quot;">​</a></h3><ul><li>您通常每天工作几个小时？每周几天？</li><li>上周实际工作了几个小时（含加班）？</li><li>加班是自愿的还是被要求的？如果您不想加班，可以拒绝吗？会有什么后果吗？</li><li>最近这个月您有几天休息日？</li></ul><h3 id="_1-3-薪资与待遇" tabindex="-1">1.3 薪资与待遇 <a class="header-anchor" href="#_1-3-薪资与待遇" aria-label="Permalink to &quot;1.3 薪资与待遇&quot;">​</a></h3><ul><li>您的工资是按月发还是按件/计时发？通常是哪一天发工资？</li><li>您会拿到工资单吗？如果有，工资单上是否清楚列出了加班费和各项扣款？</li><li>您了解自己加班费的计算方式吗？周末加班和工作日加班的待遇一样吗？</li><li>工资里有没有您不理解或认为不合理的扣款？</li><li>公司是否为您缴纳社会保险（五险）？</li></ul><h3 id="_1-4-工作环境与安全" tabindex="-1">1.4 工作环境与安全 <a class="header-anchor" href="#_1-4-工作环境与安全" aria-label="Permalink to &quot;1.4 工作环境与安全&quot;">​</a></h3><ul><li>您工作的地方通风情况怎么样？夏天/冬天温度舒适吗？</li><li>工作中是否接触化学品或有强烈气味的物质？是否有防护用品（口罩、手套、护目镜）？</li><li>您知道在发生火灾时应该从哪里逃生吗？最近多久做过一次消防演练？</li><li>如果您发现工作中有安全隐患，您会告诉谁？有没有反馈渠道？</li></ul><h3 id="_1-5-人身自由与证件" tabindex="-1">1.5 人身自由与证件 <a class="header-anchor" href="#_1-5-人身自由与证件" aria-label="Permalink to &quot;1.5 人身自由与证件&quot;">​</a></h3><ul><li>您的证件（身份证、户口本等）是否由您自己保管，还是由工厂保管？</li><li>上班时间能自由上厕所、喝水吗？</li><li>如果住在工厂宿舍，宿舍的门在晚上可以从里面打开吗？可以自由出入吗？</li></ul><h3 id="_1-6-权利与申诉" tabindex="-1">1.6 权利与申诉 <a class="header-anchor" href="#_1-6-权利与申诉" aria-label="Permalink to &quot;1.6 权利与申诉&quot;">​</a></h3><ul><li>您有没有被管理人员骂过、威胁过、或看到其他工人被骚扰的情况？</li><li>如果您对薪资或工作条件有意见，您会怎么办？会有人倾听吗？</li><li>您知道工厂有没有投诉或申诉渠道吗？用过吗？结果怎么样？</li><li>工厂有工会吗？或者有没有代表工人的委员会？</li></ul><h3 id="_1-7-综合感受" tabindex="-1">1.7 综合感受 <a class="header-anchor" href="#_1-7-综合感受" aria-label="Permalink to &quot;1.7 综合感受&quot;">​</a></h3><ul><li>总体来说，您觉得这里的工作条件怎么样？</li><li>有没有什么让您感到不满意或担忧的地方，但还没有机会说出来的？</li></ul><hr><h2 id="二、csr管理层访谈" tabindex="-1">二、CSR管理层访谈 <a class="header-anchor" href="#二、csr管理层访谈" aria-label="Permalink to &quot;二、CSR管理层访谈&quot;">​</a></h2><blockquote><p><strong>访谈对象：</strong> 人力资源经理 / 行政总监 / 合规负责人 <strong>时间：</strong> 约45-60分钟</p></blockquote><h3 id="_2-1-用工管理" tabindex="-1">2.1 用工管理 <a class="header-anchor" href="#_2-1-用工管理" aria-label="Permalink to &quot;2.1 用工管理&quot;">​</a></h3><ul><li>请介绍一下贵公司的用工构成（正式工、派遣工、季节性工人的比例）。派遣工的劳动关系和社保由谁负责？</li><li>贵公司如何识别和处理可能的强迫劳动风险？贵司是否使用了劳务中介，如何对中介进行尽职调查？</li><li>对于未成年工，贵公司有哪些专项管理措施？</li><li>当月加班率最高的部门是哪个？是什么原因导致的？公司如何监控工时合规性？</li></ul><h3 id="_2-2-薪资合规" tabindex="-1">2.2 薪资合规 <a class="header-anchor" href="#_2-2-薪资合规" aria-label="Permalink to &quot;2.2 薪资合规&quot;">​</a></h3><ul><li>贵公司的薪资结构是如何设计的？如何确保所有员工的薪资不低于当地最低工资标准？</li><li>工资的计算和发放流程是怎样的？工资单是通过什么方式传达给员工的？</li><li>过去12个月内有没有因薪资问题收到员工投诉或劳动仲裁申请？</li></ul><h3 id="_2-3-职业健康与安全" tabindex="-1">2.3 职业健康与安全 <a class="header-anchor" href="#_2-3-职业健康与安全" aria-label="Permalink to &quot;2.3 职业健康与安全&quot;">​</a></h3><ul><li>请描述贵公司的OHS管理体系。谁负责OHS日常管理？向谁报告？</li><li>过去12个月内发生过工伤事故吗？处理流程是怎样的？</li><li>化学品安全管理是如何执行的？化学品存储和处置是否有专人负责？</li></ul><h3 id="_2-4-员工关系与申诉" tabindex="-1">2.4 员工关系与申诉 <a class="header-anchor" href="#_2-4-员工关系与申诉" aria-label="Permalink to &quot;2.4 员工关系与申诉&quot;">​</a></h3><ul><li>员工的申诉渠道有哪些？过去12个月内接到了哪些类型的申诉？处理结果如何？</li><li>有没有员工因为提出申诉或投诉而受到任何形式的不利对待？</li></ul><hr><h2 id="三、环境管理访谈" tabindex="-1">三、环境管理访谈 <a class="header-anchor" href="#三、环境管理访谈" aria-label="Permalink to &quot;三、环境管理访谈&quot;">​</a></h2><blockquote><p><strong>访谈对象：</strong> EHS经理 / 环保专员 / 生产总监 <strong>时间：</strong> 约45-60分钟</p></blockquote><h3 id="_3-1-合规基础" tabindex="-1">3.1 合规基础 <a class="header-anchor" href="#_3-1-合规基础" aria-label="Permalink to &quot;3.1 合规基础&quot;">​</a></h3><ul><li>贵厂目前持有哪些环境许可证？最近一次审核是什么时候？有没有许可证即将到期？</li><li>去年有没有收到过环保部门的违规通知、罚款或被限产整改的情况？</li><li>在线监控设备（如有）的数据是实时上传给环保部门的吗？内部如何核查在线数据的准确性？</li></ul><h3 id="_3-2-污染物管理" tabindex="-1">3.2 污染物管理 <a class="header-anchor" href="#_3-2-污染物管理" aria-label="Permalink to &quot;3.2 污染物管理&quot;">​</a></h3><ul><li>贵厂的废水经过哪些处理后排放？排放口在哪里？最近一次第三方监测结果如何？</li><li>贵厂产生的固体废弃物和危险废弃物是如何分类和处置的？危废处置单位有资质吗？</li><li>贵厂在喷涂、焊接、热处理等工序中是否有VOCs或其他废气排放？管控措施是什么？</li></ul><h3 id="_3-3-能源与气候" tabindex="-1">3.3 能源与气候 <a class="header-anchor" href="#_3-3-能源与气候" aria-label="Permalink to &quot;3.3 能源与气候&quot;">​</a></h3><ul><li>过去3年贵厂的用电量是增长、下降还是持平？主要驱动因素是什么？</li><li>贵厂是否在推进可再生能源使用？目前可再生能源占比约为多少？</li><li>是否编制过温室气体排放清单？是否向本公司的碳数据采集项目提交过数据？</li></ul><h3 id="_3-4-化学品管理" tabindex="-1">3.4 化学品管理 <a class="header-anchor" href="#_3-4-化学品管理" aria-label="Permalink to &quot;3.4 化学品管理&quot;">​</a></h3><ul><li>贵厂目前使用的化学品种类有多少？是如何管理化学品清单和SDS的？</li><li>如何确保产品符合RoHS、REACH等法规要求？是否有供应商的物质合规声明？</li></ul><hr><h2 id="四、信息安全访谈" tabindex="-1">四、信息安全访谈 <a class="header-anchor" href="#四、信息安全访谈" aria-label="Permalink to &quot;四、信息安全访谈&quot;">​</a></h2><blockquote><p><strong>访谈对象：</strong> IT负责人 / 信息安全经理 / CTO/CIO <strong>时间：</strong> 约45-60分钟</p></blockquote><h3 id="_4-1-安全治理" tabindex="-1">4.1 安全治理 <a class="header-anchor" href="#_4-1-安全治理" aria-label="Permalink to &quot;4.1 安全治理&quot;">​</a></h3><ul><li>贵公司的信息安全由谁负责管理？该职责向谁汇报（向IT总监还是直接向高管）？</li><li>贵公司是否持有ISO 27001认证？如果没有，信息安全管理体系是基于哪个框架设计的？</li><li>过去12个月内有没有发生过安全事件？是如何发现和处理的？</li></ul><h3 id="_4-2-访问控制与账号管理" tabindex="-1">4.2 访问控制与账号管理 <a class="header-anchor" href="#_4-2-访问控制与账号管理" aria-label="Permalink to &quot;4.2 访问控制与账号管理&quot;">​</a></h3><ul><li>如何管理员工对关键系统的访问权限（特别是采购方的系统访问权限或技术文件访问权限）？</li><li>是否实施了多因素认证（MFA）？覆盖了哪些系统？</li><li>当员工离职时，账号是在多长时间内被注销或停用的？有没有自动化流程？</li></ul><h3 id="_4-3-漏洞与补丁管理" tabindex="-1">4.3 漏洞与补丁管理 <a class="header-anchor" href="#_4-3-漏洞与补丁管理" aria-label="Permalink to &quot;4.3 漏洞与补丁管理&quot;">​</a></h3><ul><li>贵公司的补丁管理流程是什么？关键安全补丁通常在多长时间内安装？</li><li>是否定期进行漏洞扫描或渗透测试？多久一次？最近一次测试发现了什么主要问题？</li></ul><h3 id="_4-4-供应商相关特定问题" tabindex="-1">4.4 供应商相关特定问题 <a class="header-anchor" href="#_4-4-供应商相关特定问题" aria-label="Permalink to &quot;4.4 供应商相关特定问题&quot;">​</a></h3><ul><li>贵公司访问本公司系统或存储本公司数据的员工共有多少人？他们的背景调查是如何进行的？</li><li>本公司在贵公司系统中的数据与贵公司其他客户的数据是如何隔离的？</li><li>如果发现可能影响本公司数据或系统的安全事件，贵公司的通报流程是什么？在什么时限内通知本公司？</li></ul><h3 id="_4-5-软件供应商特定问题-如适用" tabindex="-1">4.5 软件供应商特定问题（如适用） <a class="header-anchor" href="#_4-5-软件供应商特定问题-如适用" aria-label="Permalink to &quot;4.5 软件供应商特定问题（如适用）&quot;">​</a></h3><ul><li>贵公司提供的软件/固件产品是否能提供SBOM（软件物料清单）？当发现组件中有高危CVE时，贵公司的应急响应流程是什么？</li><li>贵公司的软件开发是否遵循安全开发生命周期（SSDLC）？代码审查和安全测试是在哪个阶段进行的？</li></ul><hr><h2 id="五、商业道德访谈" tabindex="-1">五、商业道德访谈 <a class="header-anchor" href="#五、商业道德访谈" aria-label="Permalink to &quot;五、商业道德访谈&quot;">​</a></h2><h3 id="_5a-财务负责人-cfo-访谈" tabindex="-1">5A. 财务负责人（CFO）访谈 <a class="header-anchor" href="#_5a-财务负责人-cfo-访谈" aria-label="Permalink to &quot;5A. 财务负责人（CFO）访谈&quot;">​</a></h3><blockquote><p><strong>适用：</strong> Level 2/3财务DD <strong>时间：</strong> 约45-60分钟</p></blockquote><ul><li>请简述贵公司过去3年的财务表现趋势。收入是增长还是收缩？驱动因素是什么？</li><li>目前贵公司的主要有息负债情况如何？到期日和再融资计划是什么？</li><li>过去12个月内，贵公司的银行授信是否有被压缩、收回或需要追加担保的情况？</li><li>贵公司最大客户的集中度约为多少？是否有客户在近期削减了订单或延长了账期？</li><li>最近一次审计意见是否为无保留意见？审计师是否就任何会计处理方式提出了关注？</li><li>目前是否有任何重大诉讼、仲裁或监管调查正在进行，可能对公司财务状况产生重大影响？</li><li>贵公司是否依赖政府补贴维持盈利？如果补贴政策改变，对盈利的影响大约是多少？</li><li>过去12个月内是否出现过应付账款逾期（&gt;30天）的情况？对哪类供应商？</li></ul><h3 id="_5b-合规-法务负责人访谈" tabindex="-1">5B. 合规/法务负责人访谈 <a class="header-anchor" href="#_5b-合规-法务负责人访谈" aria-label="Permalink to &quot;5B. 合规/法务负责人访谈&quot;">​</a></h3><blockquote><p><strong>适用：</strong> 商业道德审核（Level 1-3） <strong>时间：</strong> 约30-45分钟</p></blockquote><ul><li>贵公司反腐败合规项目的主要组成部分是什么？是由谁主导推动的？</li><li>贵公司每年的合规培训覆盖哪些人群？培训内容是如何根据岗位风险定制的？</li><li>贵公司的礼品招待政策是什么？实际执行情况如何？是否建立了礼品台账？</li><li>对于与政府部门（如许可证审批、海关）打交道的业务活动，贵公司有什么特别的合规管控？</li><li>过去3年内贵公司是否收到过关于腐败或贿赂的内部举报？是如何处理的？</li><li>贵公司如何对代理商/中间商进行反腐败尽职调查？代理合同中是否包含反腐败条款和审计权？</li></ul><h3 id="_5c-采购负责人访谈" tabindex="-1">5C. 采购负责人访谈 <a class="header-anchor" href="#_5c-采购负责人访谈" aria-label="Permalink to &quot;5C. 采购负责人访谈&quot;">​</a></h3><blockquote><p><strong>适用：</strong> 评估供应商自身的供应链道德管控 <strong>时间：</strong> 约30-45分钟</p></blockquote><ul><li>贵公司如何对其供应商进行反腐败和制裁合规筛查？</li><li>贵公司的采购决策流程中，有没有防止采购人员收受供应商回扣的机制（如双签审批、价格比较记录）？</li><li>采购人员是否被要求定期申报利益冲突？申报内容如何审查？</li><li>贵公司是否将供应商行为准则作为合同附件要求供应商签署？</li></ul><hr><h2 id="六、知识产权访谈" tabindex="-1">六、知识产权访谈 <a class="header-anchor" href="#六、知识产权访谈" aria-label="Permalink to &quot;六、知识产权访谈&quot;">​</a></h2><blockquote><p><strong>访谈对象：</strong> IP负责人 / 法务总监 / 研发/工艺总监 / HR（离职管理） <strong>时间：</strong> 约45-60分钟（可按职能分开访谈）</p></blockquote><h3 id="_6-1-ip制度与文化" tabindex="-1">6.1 IP制度与文化 <a class="header-anchor" href="#_6-1-ip制度与文化" aria-label="Permalink to &quot;6.1 IP制度与文化&quot;">​</a></h3><ul><li>贵公司的IP管理制度是由哪个部门负责执行的？员工IP保护意识的培训是如何开展的？</li><li>贵公司对员工在职期间产生的发明创造，在合同中是否有明确的归属约定？</li><li>对于研发、工艺、销售等接触核心技术或客户信息的员工，除NDA外，是否有竞业限制协议？竞业协议条款是否切实可执行？</li></ul><h3 id="_6-2-技术文件管控-重点针对客户技术文件" tabindex="-1">6.2 技术文件管控（重点针对客户技术文件） <a class="header-anchor" href="#_6-2-技术文件管控-重点针对客户技术文件" aria-label="Permalink to &quot;6.2 技术文件管控（重点针对客户技术文件）&quot;">​</a></h3><ul><li>本公司技术文件在贵方系统中是如何储存和管理的？访问权限是如何分配和审查的？</li><li>技术文件是否可以下载/打印/通过邮件转发？有哪些控制措施防止未授权外传？</li><li>如果一名有权访问本公司技术文件的员工离职，贵公司的处理流程是什么？多长时间内会注销其权限并追回相关文件？</li></ul><h3 id="_6-3-生产管控" tabindex="-1">6.3 生产管控 <a class="header-anchor" href="#_6-3-生产管控" aria-label="Permalink to &quot;6.3 生产管控&quot;">​</a></h3><ul><li>本公司委托贵方生产的产品，贵方如何确保只按授权数量生产（防止标外生产）？</li><li>所使用的模具是如何台账管理的？本公司模具是否与其他客户的模具隔离存放并有清晰标记？</li><li>防伪标签/标识的申领和使用流程是怎样的？是否有台账记录标签的使用量？</li></ul><h3 id="_6-4-ip事件处理" tabindex="-1">6.4 IP事件处理 <a class="header-anchor" href="#_6-4-ip事件处理" aria-label="Permalink to &quot;6.4 IP事件处理&quot;">​</a></h3><ul><li>过去3年内是否发生过贵方技术文件或本公司技术信息的泄露事件（或怀疑泄露）？</li><li>如果发现有员工违反保密协议或IP保护规定，贵公司的处理程序是什么？</li><li>是否曾收到过第三方的商标或专利侵权投诉？结果如何？</li></ul><hr><h2 id="七、反强迫劳动专项访谈-ilo-c190-uflpa适用场景" tabindex="-1">七、反强迫劳动专项访谈（ILO C190 / UFLPA适用场景） <a class="header-anchor" href="#七、反强迫劳动专项访谈-ilo-c190-uflpa适用场景" aria-label="Permalink to &quot;七、反强迫劳动专项访谈（ILO C190 / UFLPA适用场景）&quot;">​</a></h2><blockquote><p><strong>适用：</strong> 高风险来源地供应商；迁移工人比例高的工厂；矿产或农产品供应链中的初级生产商 <strong>重要提示：</strong> 本节访谈问题较为敏感，须由有经验的审核员在充分保护访谈者安全的前提下使用</p></blockquote><h3 id="工人访谈-专项" tabindex="-1">工人访谈（专项） <a class="header-anchor" href="#工人访谈-专项" aria-label="Permalink to &quot;工人访谈（专项）&quot;">​</a></h3><ul><li>您是在哪里出生、长大的？是怎么来到这个城市/工厂工作的？</li><li>来这里工作之前，有人向您承诺过什么条件（工资、工作性质、工作时间）？实际情况和承诺一致吗？</li><li>来这里工作的交通费、住宿费是谁支付的？</li><li>如果您想明天就离开这份工作，有任何阻碍吗？是否有欠款或者其他约束让您感觉不能离开？</li><li>您是否了解您有权利离职，而不会因此损失工资或面临惩罚？</li><li>工作期间有没有人限制过您的行动自由，比如不让您在特定时间离开工作区域？</li></ul><h3 id="管理层访谈-专项" tabindex="-1">管理层访谈（专项） <a class="header-anchor" href="#管理层访谈-专项" aria-label="Permalink to &quot;管理层访谈（专项）&quot;">​</a></h3><ul><li>贵公司招募外地或境外工人的渠道有哪些？如何核查这些渠道是否存在人口贩卖风险？</li><li>请描述贵公司的招募费政策——贵公司是否向求职者收取任何费用？是否允许劳务中介向求职者收费？</li><li>贵公司是否有工人来自贵州、新疆、西藏等偏远地区或境外（如缅甸、越南、柬埔寨）？这些工人的招募和来源如何核查？</li><li>如果某个工人想提前离职，贵公司的流程是什么？是否存在任何财务或其他约束？</li></ul>',83)])])}const b=a(r,[["render",t]]);export{q as __pageData,b as default};
